template:
:doodle {
  @grid: 1 / 100vw 100vh;
  background: #05070a;
}

@size: 100%;
background-image: @doodle(
  @grid: 1x40 / 100%;
  :after {
    content: '';
    @size: 100vw 2px;
    position: absolute;
    left: -50%;
    top: @r(0%, 100%);
    background: linear-gradient(to right, transparent, @p(#6a11cb, #2575fc, #ff00cc, #00d2ff), transparent);
    filter: blur(@r(2px, 10px));
    opacity: @r(0.2, 0.6);
    transform: rotate(@r(-10deg, 10deg));
    animation: silk-flow @r(10s, 25s) ease-in-out infinite alternate;
    animation-delay: -@r(20s);
  }
);

@keyframes silk-flow {
  0% { transform: translateY(-20px) rotate(@r(-5deg, 5deg)) scaleX(1); }
  100% { transform: translateY(20px) rotate(@r(-15deg, 15deg)) scaleX(1.2); }
}

:doodle {
  @grid: 1 / 100vw 100vh;
  background: #02040a;
  overflow: hidden;
}
background: 
  radial-gradient(circle at @r(0%, 100%) @r(0%, 100%), @p(#00d2ff, #3a7bd5, #6a11cb, #2575fc, #ff00cc) 0%, transparent @r(40%, 80%)),
  radial-gradient(circle at @r(0%, 100%) @r(0%, 100%), @p(#00f2fe, #4facfe, #43e97b, #fa709a) 0%, transparent @r(30%, 70%));
filter: blur(@r(60px, 100px));
opacity: @r(0.3, 0.6);
animation: aura-move @r(20s, 45s) linear infinite alternate;
@keyframes aura-move {
  0% { transform: translate(-15%, -15%) scale(1.2) rotate(0deg); }
  100% { transform: translate(15%, 15%) scale(1.6) rotate(20deg); }
}

:doodle {
  @grid: 12 / 100vw 100vh;
}
@size: @r(80px, 250px);
background: rgba(255, 255, 255, @r(0.02, 0.08));
backdrop-filter: blur(@r(2px, 12px));
border: 1px solid rgba(255, 255, 255, 0.1);
border-radius: @r(10px, 50px);
position: absolute;
left: @r(-10%, 110%);
top: @r(-10%, 110%);
animation: drift @r(15s, 40s) linear infinite;
@keyframes drift {
  0% { transform: translate(0, 0) rotate(0deg); opacity: 0; }
  50% { opacity: 0.8; }
  100% { transform: translate(@r(-200px, 200px), @r(-200px, 200px)) rotate(180deg); opacity: 0; }
}

:doodle {
  @grid: 1 / 100vw 100vh;
  background: #080a0f;
}
@content: @svg(
  viewBox: -50 -50 100 100;
  path*200 {
    stroke: hsla(@calc(200 + @n), 80%, 70%, @r(0.2, 0.6));
    stroke-width: @r(0.1, 0.5);
    fill: none;
    d: M @r(-50, 50) @r(-50, 50) Q @r(-20, 20) @r(-20, 20) @r(-50, 50) @r(-50, 50);
    animation: spin @r(10s, 30s) linear infinite;
  }
);
@keyframes spin { to { transform: rotate(360deg); } }

:doodle {
  @grid: 10x10 / 100vmax;
  gap: 1px;
}
background: hsla(@calc(150 + @i * 2), 70%, 60%, @r(0.2, 0.5));
clip-path: polygon(@r(100%) @r(100%), @r(100%) @r(100%), @r(100%) @r(100%));
animation: shift @r(5s, 10s) ease-in-out infinite alternate;
@keyframes shift {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.2) rotate(10deg); opacity: 0.8; }
}

:doodle {
  @grid: 1x30 / 100vw 100vh;
}
:after {
  content: @p('01', '10', '11', '00', '><', '{}', '[]', '/*');
  color: #2ecc71;
  font-family: monospace;
  font-size: @r(12px, 20px);
  position: absolute;
  left: @r(0%, 100%);
  top: -10vh;
  text-shadow: 0 0 8px #2ecc71;
  animation: rain @r(2s, 6s) linear infinite;
}
@keyframes rain { to { transform: translateY(110vh); opacity: 0; } }

:doodle {
  @grid: 1x25 / 100vw 100vh;
}
@size: @r(2px, 4px) @r(100px, 300px);
background: linear-gradient(180deg, hsla(0, 0%, 100%, @r(0.7, 1)), transparent);
border-radius: 50%;
filter: drop-shadow(0 0 8px #fff);
position: absolute;
left: @r(0%, 100%);
top: -40vh;
transform: rotate(155deg);
animation: fall @r(4s, 12s) linear infinite;
@keyframes fall {
  from { transform: translateY(0) rotate(155deg); opacity: 1; }
  to { transform: translateY(140vh) rotate(155deg); opacity: 0; }
}

:doodle {
  @grid: 10 / 100%;
  @shape: circle;
}
background: hsla(calc(240 - 6 * @x * @y), 70%, 68%, @r(0.2, 0.5));
backdrop-filter: blur(@r(2px, 5px));
border: 1px solid rgba(255, 255, 255, 0.1);
transform: scale(@r(0.3, 1));
animation: breathe @r(5s, 10s) ease-in-out infinite alternate;
@keyframes breathe { 0% { transform: scale(0.5); opacity: 0.3; } 100% { transform: scale(1.2); opacity: 0.7; } }

:doodle {
  @grid: 18 / 100vmax;
}
border-left: 1px solid hsla(@r(200, 260), 70%, 60%, @r(0.1, 0.3));
border-top: 1px solid hsla(@r(200, 260), 70%, 60%, @r(0.1, 0.3));
@random(.15) {
  background: linear-gradient(hsla(@r(360), 80%, 70%, 0.5), transparent);
  box-shadow: 0 0 15px hsla(@lr, 80%, 70%, 0.3);
  animation: glow @r(2s, 5s) ease-in-out infinite alternate;
}
@keyframes glow { 0% { opacity: 0.4; } 100% { opacity: 1; } }

:doodle {
  @grid: 8 / 100vmax;
  @shape: diamond;
}
background: hsla(@calc(300 + @i), 80%, 70%, @r(0.1, 0.4));
box-shadow: 0 0 20px hsla(@lc, 80%, 70%, 0.2);
transform: scale(@r(0.5, 1.2)) rotate(@r(360deg));
animation: pulse-glow @r(3s, 6s) ease-in-out infinite alternate;
@keyframes pulse-glow { 0% { opacity: 0.2; transform: scale(0.8); } 100% { opacity: 0.7; transform: scale(1.1); } }

:doodle {
  @grid: 1 / 100vw 100vh;
  background: #05070a;
}
@content: @svg(
  viewBox: 0 0 100 100;
  stroke: #aeacfb;
  stroke-width: .05;
  line*150 {
    draw: @r(5s, 10s);
    opacity: @r(0.1, 0.4);
    x1: @r(100); y1: @r(100);
    x2: @calc(@x1 + @r(-15, 15));
    y2: @calc(@y1 + @r(-15, 15));
  }
  circle*100 {
    r: @r(0.1, 0.3);
    cx: @r(100); cy: @r(100);
    fill: @p(#fff, #aeacfb);
    animation: twinkle @r(2s, 5s) ease-in-out infinite alternate;
  }
);
@keyframes twinkle { 0% { opacity: 0.3; } 100% { opacity: 1; } }

:doodle {
  @grid: 1 / 100vw 100vh;
  background: #0a0e14;
}
background-image: @doodle(
  @grid: 6 / 100%;
  background: hsla(@r(360), 70%, 60%, 0.1);
  border-radius: @r(30%, 70%) @r(30%, 70%) @r(30%, 70%) @r(30%, 70%);
  transform: scale(@r(0.5, 1.5)) translate(@r(-50%, 50%), @r(-50%, 50%));
  filter: blur(@r(20px, 40px));
  animation: flow @r(20s, 40s) ease-in-out infinite alternate;
);
@keyframes flow { to { transform: scale(@r(1, 2)) translate(@r(-20%, 20%), @r(-20%, 20%)) rotate(30deg); } }

:doodle {
  @grid: 7x5 / 100vw 100vh;
  gap: 20px;
}
@size: @r(100px, 200px);
background: linear-gradient(@r(360deg), hsla(260, 60%, 50%, 0.8), hsla(220, 60%, 40%, 0.6));
border-radius: 12px;
box-shadow: 0 10px 30px rgba(0,0,0,0.4);
transform: perspective(1000px) rotateX(@r(-20deg, 20deg)) rotateY(@r(-20deg, 20deg));
animation: float3d @r(8s, 15s) ease-in-out infinite alternate;
@keyframes float3d { from { transform: perspective(1000px) rotateX(-10deg) translateZ(0); } to { transform: perspective(1000px) rotateX(20deg) translateZ(50px); } }

:doodle {
  @grid: 8x6 / 100vw 100vh;
}
@size: @r(50px, 100px);
position: absolute;
left: @r(100%); top: @r(100%);
@content: @p('🚀', '🪐', '👾', '🎨', '💡', '🤖', 'H', 'E', 'C', 'T', 'O', 'R');
font-size: @r(30px, 70px);
color: @p(#ffbe0b, #fb5607, #ff006e, #8338ec, #3a86ff);
text-shadow: 0 0 15px rgba(255,255,255,0.3);
animation: bounce @r(3s, 7s) ease-in-out infinite;
@keyframes bounce { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-40px); } }
